import { use, useEffect, useState } from "react";

const allProducts = 'https://dummyjson.com/products?limit=0'
const paginatedProducts = 'https://dummyjson.com/products?limit=10&skip=0'
async function getData() {
    const resp = await fetch(paginatedProducts)
    const data = await resp.json()
    return data
}
function useData() {
    const [data, setData] = useState({
        loading: false,
        error: null,
        tableData: null
    })

   async function fetchData() {
    setData((prev) => {
        return {
          ...prev,
          loading: true
        }
    })
    try{
        const data = await getData()
        setData((prev) => {
        return {
          ...prev,
          tableData: data?.products
        }
        })
    } catch (err) {
setData((prev) => {
        return {
          ...prev,
          error: 'Error'
        }
        })
    } finally {
        setData((prev) => {
        return {
          ...prev,
          loading: false
        }
        })
    }
   }
    useEffect(() => {
      fetchData()
    },[])
    return tableData
}

export default useData
